import { Component, ElementRef, ViewChild, AfterViewInit } from '@angular/core';
import { Chessground } from 'chessground';
import { Chess } from 'chess.js';
import { ChessAgentService } from '../../services/chess-agent.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements AfterViewInit {
  @ViewChild('boardContainer') boardContainer!: ElementRef;
  private cg: any;
  private game = new Chess();

  constructor(private chessAgentService: ChessAgentService) {}

  ngAfterViewInit() {
    // Initialisation native de Chessground
    this.cg = Chessground(this.boardContainer.nativeElement, {
      fen: this.game.fen(),
      movable: {
        color: 'white',
        free: false,
        dests: this.toDests(this.game)
      },
      events: {
        move: (orig, dest) => this.onMove(orig, dest)
      }
    });
  }

  private onMove(orig: string, dest: string) {
    const move = this.game.move({ from: orig, to: dest, promotion: 'q' });
    if (move) {
      this.cg.set({ fen: this.game.fen(), movable: { dests: this.toDests(this.game) } });
      this.chessAgentService.analyzePosition(this.game.fen()).subscribe();
    }
  }

  private toDests(game: any) {
    const dests = new Map();
    game.SQUARES.forEach((s: any) => {
      const ms = game.moves({ square: s, verbose: true });
      if (ms.length) dests.set(s, ms.map((m: any) => m.to));
    });
    return dests;
  }
}
